import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useTranslation } from "react-i18next";
import { Loader2, BookOpen, Edit, Save } from "lucide-react";
import { useGlobalHandbook, useUpdateGlobalHandbook } from "@/hooks/useGlobalHandbook";
import { useUserRole } from "@/hooks/useUserRole";
import { toast } from "@/hooks/use-toast";
import { RichTextEditor } from "@/components/admin/RichTextEditor";

interface GlobalHandbookDialogProps {
  children: React.ReactNode;
}

const GlobalHandbookDialog = ({ children }: GlobalHandbookDialogProps) => {
  const { t, i18n } = useTranslation();
  const { isAdmin } = useUserRole();
  const { data: handbook, isLoading } = useGlobalHandbook();
  const updateHandbook = useUpdateGlobalHandbook();
  
  const [open, setOpen] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [activeTab, setActiveTab] = useState("zh");
  const [contentZh, setContentZh] = useState("");
  const [contentEn, setContentEn] = useState("");
  const [contentPt, setContentPt] = useState("");

  useEffect(() => {
    if (handbook) {
      setContentZh(handbook.content_zh);
      setContentEn(handbook.content_en);
      setContentPt(handbook.content_pt);
    }
  }, [handbook]);

  const getLocalizedContent = () => {
    if (!handbook) return "";
    const lang = i18n.language;
    if (lang === "zh") return handbook.content_zh || handbook.content_en || handbook.content_pt || "";
    if (lang === "pt") return handbook.content_pt || handbook.content_en || handbook.content_zh || "";
    return handbook.content_en || handbook.content_zh || handbook.content_pt || "";
  };

  const hasContent = handbook && (handbook.content_zh || handbook.content_en || handbook.content_pt);

  const handleSave = async () => {
    if (!handbook) return;
    
    try {
      await updateHandbook.mutateAsync({
        id: handbook.id,
        content_zh: contentZh,
        content_en: contentEn,
        content_pt: contentPt,
      });
      toast({
        title: t("common.success"),
        description: t("activities.handbook.updateSuccess"),
      });
      setIsEditing(false);
    } catch (error) {
      toast({
        title: t("common.error"),
        description: t("activities.handbook.updateError"),
        variant: "destructive",
      });
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        {children}
      </DialogTrigger>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <div className="flex items-center gap-2">
            <BookOpen className="w-5 h-5 text-primary" />
            <DialogTitle>{t("activities.handbook.title")}</DialogTitle>
          </div>
        </DialogHeader>
        
        {isLoading ? (
          <div className="flex justify-center py-8">
            <Loader2 className="w-6 h-6 animate-spin text-primary" />
          </div>
        ) : isEditing && isAdmin ? (
          <div className="space-y-4">
            <Tabs value={activeTab} onValueChange={setActiveTab}>
              <TabsList className="grid w-full grid-cols-3">
                <TabsTrigger value="zh">中文</TabsTrigger>
                <TabsTrigger value="en">English</TabsTrigger>
                <TabsTrigger value="pt">Português</TabsTrigger>
              </TabsList>
              
              <TabsContent value="zh" className="mt-4">
                <RichTextEditor
                  value={contentZh}
                  onChange={setContentZh}
                  placeholder="请输入中文活动手册内容..."
                />
              </TabsContent>
              
              <TabsContent value="en" className="mt-4">
                <RichTextEditor
                  value={contentEn}
                  onChange={setContentEn}
                  placeholder="Enter English activity handbook content..."
                />
              </TabsContent>
              
              <TabsContent value="pt" className="mt-4">
                <RichTextEditor
                  value={contentPt}
                  onChange={setContentPt}
                  placeholder="Digite o conteúdo do manual da atividade em português..."
                />
              </TabsContent>
            </Tabs>
          </div>
        ) : (
          <div className="space-y-4">
            {hasContent ? (
              <div 
                className="prose prose-sm dark:prose-invert max-w-none"
                dangerouslySetInnerHTML={{ __html: getLocalizedContent() }}
              />
            ) : (
              <div className="text-center py-8 text-muted-foreground">
                <BookOpen className="w-12 h-12 mx-auto mb-3 opacity-50" />
                <p>{t("activities.handbook.empty")}</p>
                {isAdmin && (
                  <p className="text-sm mt-2">{t("activities.handbook.addPrompt")}</p>
                )}
              </div>
            )}
          </div>
        )}
        
        <DialogFooter className="gap-2 sm:gap-0">
          {isEditing ? (
            <>
              <Button variant="outline" onClick={() => setIsEditing(false)}>
                {t("common.cancel")}
              </Button>
              <Button onClick={handleSave} disabled={updateHandbook.isPending}>
                {updateHandbook.isPending ? (
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                ) : (
                  <Save className="w-4 h-4 mr-2" />
                )}
                {t("common.save")}
              </Button>
            </>
          ) : (
            isAdmin && (
              <Button onClick={() => setIsEditing(true)}>
                <Edit className="w-4 h-4 mr-2" />
                {hasContent ? t("common.edit") : t("activities.handbook.add")}
              </Button>
            )
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};

export default GlobalHandbookDialog;
