import { useState, useEffect } from "react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuSeparator, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Share2, MessageCircle, Link2, Gift, Loader2, Instagram, CheckCircle } from "lucide-react";
import { useTranslation } from "react-i18next";
import { toast } from "sonner";
import { useIsMobile } from "@/hooks/use-mobile";
import { isIOSWebView, isInWebView, isAndroidWebView } from "@/lib/externalLinks";
import { smartShare } from "@/lib/share";

interface ShareForCouponDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  activityTitle: string;
  activityId: string;
  onShareComplete: () => void;
  onShareAction?: () => void; // Called whenever user shares, regardless of coupon status
  isProcessing?: boolean;
  hasAlreadyClaimed?: boolean;
}

export const ShareForCouponDialog = ({
  open,
  onOpenChange,
  activityTitle,
  activityId,
  onShareComplete,
  onShareAction,
  isProcessing = false,
  hasAlreadyClaimed = false,
}: ShareForCouponDialogProps) => {
  const { t } = useTranslation();
  const isMobile = useIsMobile();
  const [hasShared, setHasShared] = useState(false);
  const [supportsNativeShare, setSupportsNativeShare] = useState(false);
  const isWebView = isIOSWebView() || isAndroidWebView();

  useEffect(() => {
    setSupportsNativeShare(
      typeof navigator !== 'undefined' && 
      !!navigator.share && 
      typeof navigator.canShare === 'function' &&
      !isWebView // Don't use native share in WebView
    );
  }, [isWebView]);

  const handleCopyLink = async () => {
    try {
      await navigator.clipboard.writeText(window.location.href);
      toast.success(t("common.linkCopied"));
      setHasShared(true);
      // Trigger share action callback
      onShareAction?.();
    } catch (error) {
      console.error("Error copying link:", error);
      toast.error(t("common.shareError"));
    }
  };

  const handleShareToPlatform = (platform: string) => {
    const url = encodeURIComponent(window.location.href);
    const text = encodeURIComponent(`${activityTitle} - Xiaoxiong Market`);

    let shareUrl = "";
    switch (platform) {
      case "whatsapp":
        shareUrl = `https://wa.me/?text=${text}%20${url}`;
        break;
      case "facebook":
        shareUrl = `https://www.facebook.com/sharer/sharer.php?u=${url}`;
        break;
      case "twitter":
        shareUrl = `https://twitter.com/intent/tweet?text=${text}&url=${url}`;
        break;
      case "telegram":
        shareUrl = `https://t.me/share/url?url=${url}&text=${text}`;
        break;
      case "linkedin":
        shareUrl = `https://www.linkedin.com/sharing/share-offsite/?url=${url}`;
        break;
      case "reddit":
        shareUrl = `https://reddit.com/submit?url=${url}&title=${text}`;
        break;
      case "line":
        shareUrl = `https://social-plugins.line.me/lineit/share?url=${url}`;
        break;
      case "wechat":
        handleCopyLink();
        toast.info(t("sharing.copiedForWeChat"));
        return;
      case "instagram":
        handleCopyLink();
        toast.info(t("sharing.copiedForInstagram"));
        return;
      default:
        return;
    }

    // Use appropriate method based on environment
    if (isIOSWebView() || isInWebView()) {
      window.location.href = shareUrl;
    } else {
      window.open(shareUrl, "_blank", "noopener,noreferrer");
    }
    setHasShared(true);
    // Trigger share action callback
    onShareAction?.();
  };

  const handleNativeShare = async () => {
    const shareData = {
      title: activityTitle,
      text: `${activityTitle} - Xiaoxiong Market`,
      url: window.location.href,
    };

    // In WebView, directly copy to clipboard
    if (isWebView) {
      await handleCopyLink();
      return;
    }

    try {
      if (navigator.share && navigator.canShare && navigator.canShare(shareData)) {
        await navigator.share(shareData);
        setHasShared(true);
        // Trigger share action callback
        onShareAction?.();
      } else {
        handleCopyLink();
      }
    } catch (error) {
      if ((error as Error).name !== "AbortError") {
        console.error("Error sharing:", error);
        toast.error(t("common.shareError"));
      }
    }
  };

  const handleConfirmShare = () => {
    if (hasShared) {
      onShareComplete();
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            {hasAlreadyClaimed ? (
              <CheckCircle className="w-5 h-5 text-primary" />
            ) : (
              <Gift className="w-5 h-5 text-primary" />
            )}
            {t("shareDialog.title")}
          </DialogTitle>
          <DialogDescription className="space-y-2">
            {hasAlreadyClaimed ? (
              <p className="text-primary font-medium">{t("shareDialog.alreadyShared")}</p>
            ) : (
              <>
                <p>{t("shareDialog.description")}</p>
                <p className="text-sm text-muted-foreground">
                  {t("shareDialog.hint")}
                </p>
              </>
            )}
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          {/* Share options */}
          <div className="flex flex-col gap-2">
            {/* On mobile with native share support, show native share as primary option */}
            {isMobile && supportsNativeShare ? (
              <Button onClick={handleNativeShare} className="w-full" variant="default">
                <Share2 className="w-4 h-4 mr-2" />
                {t("sharing.shareToApps")}
              </Button>
            ) : (
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button className="w-full" variant="default">
                    <Share2 className="w-4 h-4 mr-2" />
                    {t("sharing.selectPlatform")}
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent className="w-56">
                  {supportsNativeShare && (
                    <>
                      <DropdownMenuItem onClick={handleNativeShare}>
                        <Share2 className="w-4 h-4 mr-2" />
                        {t("sharing.systemShare")}
                      </DropdownMenuItem>
                      <DropdownMenuSeparator />
                    </>
                  )}
                  <DropdownMenuItem onClick={() => handleShareToPlatform("wechat")}>
                    <MessageCircle className="w-4 h-4 mr-2" />
                    WeChat
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => handleShareToPlatform("instagram")}>
                    <Instagram className="w-4 h-4 mr-2" />
                    Instagram
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => handleShareToPlatform("whatsapp")}>
                    <MessageCircle className="w-4 h-4 mr-2" />
                    WhatsApp
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => handleShareToPlatform("facebook")}>
                    <Share2 className="w-4 h-4 mr-2" />
                    Facebook
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => handleShareToPlatform("twitter")}>
                    <Share2 className="w-4 h-4 mr-2" />
                    X (Twitter)
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => handleShareToPlatform("telegram")}>
                    <MessageCircle className="w-4 h-4 mr-2" />
                    Telegram
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => handleShareToPlatform("linkedin")}>
                    <Share2 className="w-4 h-4 mr-2" />
                    LinkedIn
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => handleShareToPlatform("line")}>
                    <MessageCircle className="w-4 h-4 mr-2" />
                    LINE
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => handleShareToPlatform("reddit")}>
                    <Share2 className="w-4 h-4 mr-2" />
                    Reddit
                  </DropdownMenuItem>
                  <DropdownMenuSeparator />
                  <DropdownMenuItem onClick={handleCopyLink}>
                    <Link2 className="w-4 h-4 mr-2" />
                    {t("common.copyLink")}
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            )}
          </div>

          {/* Confirm button - only show if not already claimed */}
          {!hasAlreadyClaimed && (
            <Button
              onClick={handleConfirmShare}
              disabled={!hasShared || isProcessing}
              className="w-full"
              variant={hasShared ? "default" : "secondary"}
            >
              {isProcessing ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  {t("shareDialog.claiming")}
                </>
              ) : hasShared ? (
                <>
                  <Gift className="w-4 h-4 mr-2" />
                  {t("shareDialog.confirmButton")}
                </>
              ) : (
                t("shareDialog.shareFirst")
              )}
            </Button>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
};
