import { useEffect, useRef, memo, useState } from "react";
import mapboxgl from "mapbox-gl";
import "mapbox-gl/dist/mapbox-gl.css";
import { ActivityRestaurant } from "@/hooks/useActivities";
import { isIOSDevice, isIOSWebView } from "@/lib/externalLinks";
import { AlertTriangle, MapPin } from "lucide-react";
import { Button } from "@/components/ui/button";
import { useTranslation } from "react-i18next";
import mapIcon from "@/assets/map-icon.png";

interface ActivityParticipationMapProps {
  restaurants: ActivityRestaurant[];
  onMarkerClick?: (restaurantId: string) => void;
}

const ActivityParticipationMap = memo(({ restaurants, onMarkerClick }: ActivityParticipationMapProps) => {
  const { t } = useTranslation();
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<mapboxgl.Map | null>(null);
  const markers = useRef<mapboxgl.Marker[]>([]);
  const [mapLoaded, setMapLoaded] = useState(false);
  const [mapError, setMapError] = useState<string | null>(null);
  const currentPopup = useRef<mapboxgl.Popup | null>(null);

  useEffect(() => {
    if (!mapContainer.current || map.current) return;

    const MAPBOX_TOKEN = import.meta.env.VITE_MAPBOX_TOKEN;
    if (!MAPBOX_TOKEN) {
      console.warn('[ActivityMap] No Mapbox token found');
      return;
    }

    // Check WebGL support
    if (!mapboxgl.supported()) {
      console.warn('[ActivityMap] WebGL not supported', {
        isIOSDevice: isIOSDevice(),
        isIOSWebView: isIOSWebView(),
        userAgent: navigator.userAgent
      });
      setMapError(t('map.webglNotSupported', 'Your browser does not support map display'));
      return;
    }

    // Wait for container to have valid dimensions
    const initMap = () => {
      if (!mapContainer.current) return;
      
      const rect = mapContainer.current.getBoundingClientRect();
      
      if (rect.width === 0 || rect.height === 0) {
        setTimeout(initMap, 100);
        return;
      }

      try {
        mapboxgl.accessToken = MAPBOX_TOKEN;

        // Calculate center based on all restaurants
        const avgLat = restaurants.reduce((sum, r) => sum + Number(r.restaurants.lat || 0), 0) / restaurants.length;
        const avgLng = restaurants.reduce((sum, r) => sum + Number(r.restaurants.lng || 0), 0) / restaurants.length;

        map.current = new mapboxgl.Map({
          container: mapContainer.current,
          style: "mapbox://styles/mapbox/light-v11",
          center: [avgLng, avgLat],
          zoom: 12,
          cooperativeGestures: true,
          doubleClickZoom: false,
        });

        map.current.on('error', (e) => {
          console.error('[ActivityMap] Map error:', e);
          setMapError(t('map.loadError', 'Map failed to load'));
        });

        map.current.addControl(new mapboxgl.NavigationControl(), "top-right");

        map.current.on("load", () => {
          setMapLoaded(true);
        });
      } catch (error) {
        console.error('[ActivityMap] Failed to initialize map:', error);
        setMapError(t('map.loadError', 'Map failed to load'));
      }
    };

    initMap();

    return () => {
      markers.current.forEach(marker => marker.remove());
      markers.current = [];
      if (currentPopup.current) {
        currentPopup.current.remove();
        currentPopup.current = null;
      }
      map.current?.remove();
      map.current = null;
      setMapLoaded(false);
    };
  }, [restaurants.length, t]);

  useEffect(() => {
    if (!map.current || !mapLoaded || restaurants.length === 0) return;

    // Add markers using default Mapbox style
    const addMarkers = () => {
      // Clear existing markers
      markers.current.forEach(marker => marker.remove());
      markers.current = [];
      
      // Clear existing popup
      if (currentPopup.current) {
        currentPopup.current.remove();
        currentPopup.current = null;
      }

      restaurants.forEach((restaurant) => {
        const lat = Number(restaurant.restaurants.lat);
        const lng = Number(restaurant.restaurants.lng);

        if (isNaN(lat) || isNaN(lng)) return;

        const popupContent = document.createElement('div');
        popupContent.className = 'p-3 min-w-[200px]';
        popupContent.innerHTML = `
          <div class="space-y-2">
            <h3 class="font-bold text-base text-foreground">${restaurant.restaurants.name}</h3>
            <p class="text-xs text-muted-foreground">${restaurant.restaurants.address}</p>
          </div>
        `;

        const popup = new mapboxgl.Popup({ 
          offset: 25,
          closeButton: true,
          closeOnClick: false,
          closeOnMove: false,
          maxWidth: '300px'
        })
          .setLngLat([lng, lat])
          .setDOMContent(popupContent);

        const el = document.createElement('div');
        el.className = 'custom-marker';
        el.style.backgroundImage = `url(${mapIcon})`;
        el.style.width = '40px';
        el.style.height = '40px';
        el.style.backgroundSize = 'contain';
        el.style.backgroundRepeat = 'no-repeat';
        el.style.backgroundPosition = 'center';
        el.style.cursor = 'pointer';

        const marker = new mapboxgl.Marker({ 
          element: el,
          draggable: false
        })
          .setLngLat([lng, lat])
          .addTo(map.current!);

        const markerElement = marker.getElement();
        markerElement.style.cursor = 'pointer';
        
        // Handle marker click with proper popup management
        const handleMarkerClick = (e: MouseEvent) => {
          e.stopPropagation();
          e.preventDefault();
          
          // Close previous popup if exists
          if (currentPopup.current && currentPopup.current !== popup) {
            currentPopup.current.remove();
          }
          
          // Open new popup
          popup.addTo(map.current!);
          currentPopup.current = popup;
          
          // Zoom to marker
          map.current!.easeTo({
            center: [lng, lat],
            zoom: 17,
            duration: 800,
          });
          
          if (onMarkerClick) {
            onMarkerClick(restaurant.restaurant_id);
          }
        };
        
        markerElement.addEventListener('click', handleMarkerClick, true);
        
        // Handle popup close
        popup.on('close', () => {
          if (currentPopup.current === popup) {
            currentPopup.current = null;
          }
        });

        markers.current.push(marker);
      });

      // Fit bounds to show all markers
      if (restaurants.length > 1) {
        const bounds = new mapboxgl.LngLatBounds();
        restaurants.forEach((restaurant) => {
          const lat = Number(restaurant.restaurants.lat);
          const lng = Number(restaurant.restaurants.lng);
          if (!isNaN(lat) && !isNaN(lng)) {
            bounds.extend([lng, lat]);
          }
        });
        map.current?.fitBounds(bounds, { padding: 50, maxZoom: 14 });
      }
    };

    addMarkers();
  }, [restaurants, mapLoaded, onMarkerClick]);

  if (restaurants.length === 0) return null;

  // Show error fallback UI
  if (mapError) {
    return (
      <div className="w-full h-[350px] rounded-lg bg-muted/50 flex flex-col items-center justify-center p-6 text-center">
        <AlertTriangle className="w-10 h-10 text-muted-foreground mb-3" />
        <p className="text-muted-foreground text-sm mb-2">{mapError}</p>
        <p className="text-xs text-muted-foreground mb-3">
          {t('map.viewListInstead', 'Please view the restaurant list below')}
        </p>
        {isIOSWebView() && (
          <Button
            variant="outline"
            size="sm"
            onClick={() => window.open(window.location.href, '_blank')}
          >
            <MapPin className="w-4 h-4 mr-2" />
            {t('map.openInBrowser', 'Open in Browser')}
          </Button>
        )}
      </div>
    );
  }

  return <div ref={mapContainer} className="w-full h-[350px] rounded-lg" />;
});

ActivityParticipationMap.displayName = "ActivityParticipationMap";

export default ActivityParticipationMap;
