import { formatTrademarkSymbols } from "@/lib/textFormatting";
import { useParams, Link, useLocation, useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger, DropdownMenuSeparator } from "@/components/ui/dropdown-menu";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/components/ui/alert-dialog";
import { Checkbox } from "@/components/ui/checkbox";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible";
import { Calendar, Users, MapPin, Star, ChevronLeft, Loader2, Check, Store, ChevronDown, ChevronUp, Navigation, Share2, ShieldAlert, Link2, MessageCircle, UtensilsCrossed, ShoppingBag, ExternalLink, BookOpen, Gift, Tag, UserCircle, FileText, Heart, FileEdit } from "lucide-react";
import ExternalLinkConfirmDialog from "@/components/ExternalLinkConfirmDialog";
import CommunityEntryCTA from "@/components/CommunityEntryCTA";
import GuessYouLike from "@/components/GuessYouLike";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import platformLogo from "@/assets/xiaoxiong-logo-v3.png";
import i18n from "@/i18n/config";
import React, { useMemo, useCallback, useState, useRef, useEffect } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { PullToRefresh } from "@/components/PullToRefresh";
import { useActivity, useActivityRestaurants, useToggleSubscription, useSubscriptions, useSubscriberCount, useShareCount, useActivityCreator, useRecordShare, ActivityCreator } from "@/hooks/useActivities";
import { useActivityDetailRealtime } from "@/hooks/useActivityRealtime";
import { useMerchantRestaurants, useMyParticipatingRestaurants, useToggleRestaurantParticipation } from "@/hooks/useActivityParticipation";
import { useAuth } from "@/contexts/AuthContext";
import { useUserRole } from "@/hooks/useUserRole";
import { useProfile } from "@/hooks/useProfile";
import { useTranslation, Trans } from "react-i18next";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { format } from "date-fns";
import RestaurantComments from "@/components/RestaurantComments";
import ActivityParticipationMap from "@/components/ActivityParticipationMap";
import SelectRestaurantsDialog from "@/components/SelectRestaurantsDialog";
import ReportDialog from "@/components/ReportDialog";
import ActivityTermsAgreement from "@/components/ActivityTermsAgreement";
import GlobalHandbookDialog from "@/components/GlobalHandbookDialog";
import LocationPermissionDialog from "@/components/LocationPermissionDialog";
import { ShareForCouponDialog } from "@/components/ShareForCouponDialog";
import { getUserLocation, calculateDistance } from "@/lib/geolocation";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
import { useIsMobile } from "@/hooks/use-mobile";
import { useActivityCouponTemplates, useHasSharedCoupon, useClaimCouponFromTemplate, useGlobalShareCouponTemplate } from "@/hooks/useCoupons";
import { usePageView } from "@/hooks/usePageView";
import { ActivityDetailSkeleton } from "@/components/skeletons";
import { ActivityShareCount } from "@/components/ActivityShareCount";
import { ActivitySubscriberCount } from "@/components/ActivitySubscriberCount";
import { useSmartShare, ShareDrawer } from "@/components/ShareDrawer";
import TranslateButton from "@/components/TranslateButton";
import { useSmartBack } from "@/hooks/useSmartBack";

const ActivityDetail = () => {
  const { id } = useParams<{ id: string }>();
  const location = useLocation();
  const navigate = useNavigate();
  const { t } = useTranslation();
  const { user } = useAuth();
  const { isMerchant, isSupervisor, isAdmin } = useUserRole();
  const { data: profile } = useProfile();
  const { localizeActivity, localizeRestaurant, currentLang } = useLocalizedContent();
  const isMobile = useIsMobile();
  const [isRestaurantsOpen, setIsRestaurantsOpen] = React.useState(false);
  const [showAllRestaurants, setShowAllRestaurants] = React.useState(false);
  const [userLocation, setUserLocation] = React.useState<{ lat: number; lng: number } | null>(null);
  const [locationEnabled, setLocationEnabled] = React.useState(false);
  const [isLoadingLocation, setIsLoadingLocation] = React.useState(false);
  const [selectRestaurantsDialogOpen, setSelectRestaurantsDialogOpen] = React.useState(false);
  const [termsDialogOpen, setTermsDialogOpen] = React.useState(false);
  const [showCouponHint, setShowCouponHint] = React.useState(true);
  const [showShareDialog, setShowShareDialog] = React.useState(false);
  const [showLocationDialog, setShowLocationDialog] = React.useState(false);
  const [isClaimingCoupon, setIsClaimingCoupon] = React.useState(false);
  const [showLoginDialog, setShowLoginDialog] = React.useState(false);
  const [externalLinkDialogOpen, setExternalLinkDialogOpen] = React.useState(false);
  const [pendingExternalUrl, setPendingExternalUrl] = React.useState<string | null>(null);
  const [translatedContent, setTranslatedContent] = React.useState<string | null>(null);
  const queryClient = useQueryClient();
  const { share: smartShareFn, DrawerComponent: SmartShareDrawer } = useSmartShare();

  // Pull-to-refresh handler - clears cache and forces fresh data
  const handleRefresh = useCallback(async () => {
    // Clear caches first
    queryClient.removeQueries({ queryKey: ['activity', id] });
    queryClient.removeQueries({ queryKey: ['activity-restaurants', id] });
    queryClient.removeQueries({ queryKey: ['subscriber-count', id] });
    queryClient.removeQueries({ queryKey: ['share-count', id] });
    queryClient.removeQueries({ queryKey: ['comments', id] });
    
    // Refetch with fresh data
    await Promise.all([
      queryClient.invalidateQueries({ queryKey: ['activity', id] }),
      queryClient.invalidateQueries({ queryKey: ['activity-restaurants', id] }),
      queryClient.invalidateQueries({ queryKey: ['subscriber-count', id] }),
      queryClient.invalidateQueries({ queryKey: ['share-count', id] }),
      queryClient.invalidateQueries({ queryKey: ['comments', id] }),
    ]);
  }, [queryClient, id]);

  // Handler for external link with confirmation dialog (iOS compatible)
  // Requires login first, consistent with restaurant detail page behavior
  const handleExternalLinkClick = useCallback(async (websiteUrl: string, restaurantId?: string) => {
    try {
      const url = new URL(websiteUrl);
      if (user && restaurantId) {
        try {
          const { data } = await supabase.functions.invoke('generate-private-token', {
            body: { restaurant_id: restaurantId }
          });
          if (data?.token) {
            url.searchParams.set('token', data.token);
          }
        } catch (tokenErr) {
          console.error('Token generation failed:', tokenErr);
        }
      }
      setPendingExternalUrl(url.toString());
      setExternalLinkDialogOpen(true);
    } catch (e) {
      console.error('Invalid URL:', e);
    }
  }, [user]);

  const handleConfirmExternalLink = useCallback(() => {
    if (pendingExternalUrl) {
      // Use location.href for iOS WebView compatibility
      // This ensures the link works in WeChat, TikTok, and other in-app browsers
      const isIOSWebView = /iPad|iPhone|iPod/.test(navigator.userAgent) && 
        !/Safari\//.test(navigator.userAgent) && 
        !(window as any).Capacitor?.isNativePlatform?.();
      
      if (isIOSWebView) {
        window.location.href = pendingExternalUrl;
      } else {
        window.open(pendingExternalUrl, '_blank');
      }
    }
    setExternalLinkDialogOpen(false);
    setPendingExternalUrl(null);
  }, [pendingExternalUrl]);

  // Track page view
  usePageView({ pageType: "activity", targetId: id });

  // Enable realtime updates for this activity
  useActivityDetailRealtime(id!);
  
  const { data: activityCouponTemplates = [] } = useActivityCouponTemplates(id!);
  const { data: hasSharedCoupon = false } = useHasSharedCoupon(id!);
  const { data: globalShareCouponTemplate } = useGlobalShareCouponTemplate();
  const claimCoupon = useClaimCouponFromTemplate();
  
  // Check if there's any coupon available (activity-specific OR global share coupon)
  const hasCouponAvailable = activityCouponTemplates.length > 0 || !!globalShareCouponTemplate;
  
  // Memoize marker click handler to prevent map reloading
  const handleMarkerClick = React.useCallback((restaurantId: string) => {
    navigate(`/restaurant/${restaurantId}`, {
      state: { fromActivity: id }
    });
  }, [navigate, id]);
  
  // Smart back navigation - uses browser history when available
  const goBack = useSmartBack("/activities");

  const { data: activity, isLoading: activityLoading } = useActivity(id!);
  const { data: activityRestaurants, isLoading: restaurantsLoading } = useActivityRestaurants(id!);
  const { data: subscriptions = [] } = useSubscriptions();
  const subscribedIds = subscriptions.map(sub => sub.activity_id);
  const { data: subscriberCount = 0 } = useSubscriberCount(id!);
  const { data: shareCount = 0 } = useShareCount(id!);
  const recordShare = useRecordShare();
  const { data: creator } = useActivityCreator(activity?.creator_id);
  const toggleSubscription = useToggleSubscription();

  // For merchant/supervisor
  const { data: myRestaurants = [] } = useMerchantRestaurants();
  const { data: participatingRestaurantIds = [] } = useMyParticipatingRestaurants(id!);
  const toggleParticipation = useToggleRestaurantParticipation();

  const localizedActivity = activity ? localizeActivity(activity) : null;
  const isSubscribed = activity ? subscribedIds.includes(activity.id) : false;
  const isMerchantOrSupervisor = isMerchant || isSupervisor;

  const handleToggleSubscription = useCallback(() => {
    if (!user || !activity) {
      return;
    }
    toggleSubscription.mutate(activity.id);
  }, [user, activity, toggleSubscription]);

  // Check participation status for button text
  const participatingCount = myRestaurants.filter(r => 
    participatingRestaurantIds.includes(r.id)
  ).length;
  const hasParticipatingRestaurants = participatingCount > 0;
  const allRestaurantsParticipating = participatingCount === myRestaurants.length;
  const someRestaurantsParticipating = participatingCount > 0 && participatingCount < myRestaurants.length;

  const handleToggleActivityParticipation = useCallback(() => {
    if (!activity || !isMerchantOrSupervisor || myRestaurants.length === 0) return;
    
    // Open dialog to let supervisor select restaurants
    if (isSupervisor) {
      setSelectRestaurantsDialogOpen(true);
    } else {
      // For merchants, toggle all restaurants directly
      if (hasParticipatingRestaurants) {
        // Remove all merchant's restaurants from activity
        for (const restaurant of myRestaurants) {
          if (participatingRestaurantIds.includes(restaurant.id)) {
            toggleParticipation.mutate({
              activityId: activity.id,
              restaurantId: restaurant.id,
            });
          }
        }
      } else {
        // Add all merchant's restaurants to activity
        for (const restaurant of myRestaurants) {
          toggleParticipation.mutate({
            activityId: activity.id,
            restaurantId: restaurant.id,
          });
        }
      }
    }
  }, [activity, isMerchantOrSupervisor, myRestaurants, isSupervisor, hasParticipatingRestaurants, participatingRestaurantIds, toggleParticipation]);

  const handleConfirmRestaurantSelection = useCallback((selectedRestaurantIds: string[]) => {
    if (!activity) return;

    // Determine which restaurants to add and which to remove
    const toAdd = selectedRestaurantIds.filter(id => !participatingRestaurantIds.includes(id));
    const toRemove = participatingRestaurantIds.filter(id => !selectedRestaurantIds.includes(id));

    // Add restaurants
    toAdd.forEach(restaurantId => {
      toggleParticipation.mutate({
        activityId: activity.id,
        restaurantId,
      });
    });

    // Remove restaurants
    toRemove.forEach(restaurantId => {
      toggleParticipation.mutate({
        activityId: activity.id,
        restaurantId,
      });
    });

    setSelectRestaurantsDialogOpen(false);
  }, [activity, participatingRestaurantIds, toggleParticipation]);

  const handleRequestLocation = useCallback(() => {
    setShowLocationDialog(true);
  }, []);

  const requestLocation = useCallback(async () => {
    setShowLocationDialog(false);
    setIsLoadingLocation(true);
    try {
      const position = await getUserLocation();
      setUserLocation({
        lat: position.coords.latitude,
        lng: position.coords.longitude,
      });
      setLocationEnabled(true);
      toast.success(t("map.locationEnabled"));
    } catch (error) {
      console.error("Location error:", error);
      setLocationEnabled(false);
    } finally {
      setIsLoadingLocation(false);
    }
  }, [t]);

  const handleDisableLocation = useCallback(() => {
    setUserLocation(null);
    setLocationEnabled(false);
  }, []);

  // Auto-hide coupon hint after 3 seconds
  React.useEffect(() => {
    if (user && hasCouponAvailable && !hasSharedCoupon && showCouponHint) {
      const timer = setTimeout(() => {
        setShowCouponHint(false);
      }, 3000);

      return () => clearTimeout(timer);
    }
  }, [user, hasCouponAvailable, hasSharedCoupon, showCouponHint]);

  const handleCopyLink = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(window.location.href);
      toast.success(t("common.linkCopied"));
    } catch (error) {
      console.error("Error copying link:", error);
      toast.error(t("common.shareError"));
    }
  }, [t]);

  const handleNativeShare = useCallback(async () => {
    if (!activity || !localizedActivity) return;
    
    smartShareFn({
      title: localizedActivity.title,
      text: `${localizedActivity.title} - Xiaoxiong Market\n\n${localizedActivity.content.replace(/<[^>]*>/g, '').substring(0, 200)}...`,
      url: window.location.href,
    }, () => {
      toast.success(t("common.shareSuccess"));
    });
  }, [activity, localizedActivity, smartShareFn, t]);

  const handleShareClick = useCallback(() => {
    if (!activity || !localizedActivity) return;
    
    // Check if user is logged in - always require login for share
    if (!user) {
      setShowLoginDialog(true);
      return;
    }
    
    // If user is logged in and coupon is available, show the share dialog
    // Dialog will show "already claimed" state if user has already claimed
    if (hasCouponAvailable) {
      setShowShareDialog(true);
    } else {
      // For users with no coupon available, just do normal share
      handleNativeShare();
      // Record share for logged-in users
      recordShare.mutateAsync({ activityId: id!, userId: user.id }).catch(() => {});
    }
  }, [activity, localizedActivity, user, hasCouponAvailable, handleNativeShare, recordShare, id]);

  const handleShareComplete = useCallback(async () => {
    if (!activity || !user) return;
    
    setIsClaimingCoupon(true);
    try {
      // Record share
      await recordShare.mutateAsync({ activityId: id!, userId: user.id });
      
      // Claim coupon
      const template = activityCouponTemplates.length > 0 
        ? activityCouponTemplates[0] 
        : globalShareCouponTemplate;
      
      if (template) {
        await claimCoupon.mutateAsync({
          templateId: template.id,
          activityId: id!,
          source: "share",
        });
        toast.success(t("coupon.claimSuccess"));
      }
      
      setShowShareDialog(false);
    } catch (error) {
      console.error("Error claiming coupon:", error);
      toast.error(t("common.error"));
    } finally {
      setIsClaimingCoupon(false);
    }
  }, [activity, user, recordShare, id, activityCouponTemplates, globalShareCouponTemplate, claimCoupon, t]);

  // Handler for when user actually shares (regardless of coupon claim)
  const handleShareAction = useCallback(() => {
    if (!user || !id) return;
    // Record share in background
    recordShare.mutateAsync({ activityId: id, userId: user.id }).catch((error) => {
      console.log("Share already recorded or error:", error);
    });
  }, [user, id, recordShare]);

  // Calculate distance for all restaurants and sort by distance if location is available, otherwise by rating
  const filteredRestaurants = useMemo(() => {
    if (!activityRestaurants) return [];
    
    // Calculate distance for all restaurants if user location is available
    const restaurantsWithDistance = activityRestaurants.map((ar) => {
      if (userLocation) {
        const distance = calculateDistance(
          userLocation.lat,
          userLocation.lng,
          Number(ar.restaurants.lat),
          Number(ar.restaurants.lng)
        );
        return { ...ar, distance };
      }
      return { ...ar, distance: undefined as number | undefined };
    });

    // Sort by distance (nearest first) if location is available, otherwise by rating (highest first)
    if (locationEnabled && userLocation) {
      return restaurantsWithDistance.sort((a, b) => {
        if (a.distance !== undefined && b.distance !== undefined) {
          return a.distance - b.distance;
        }
        return 0;
      });
    }

    // Sort by rating (highest first) when no location
    return restaurantsWithDistance.sort((a, b) => {
      const ratingA = Number(a.restaurants.rating) || 0;
      const ratingB = Number(b.restaurants.rating) || 0;
      return ratingB - ratingA;
    });
  }, [activityRestaurants, locationEnabled, userLocation]);

  if (activityLoading) {
    return <ActivityDetailSkeleton />;
  }

  // Draft activities should not be accessible to regular users - admins can preview
  if (!activity || !localizedActivity || (activity.status === "draft" && !isAdmin)) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <p className="text-xl text-muted-foreground">{t("error.notFound")}</p>
          <Button className="mt-4" onClick={goBack}>
            {t("common.back")}
          </Button>
        </div>
      </div>
    );
  }

  const startDate = new Date(activity.start_date);
  const endDate = activity.end_date ? new Date(activity.end_date) : null;
  // If no end_date, activity is ongoing indefinitely
  const isOngoing = endDate ? new Date() <= endDate : new Date() >= startDate;

  return (
    <PullToRefresh onRefresh={handleRefresh}>
    <div className="min-h-screen bg-secondary/20">
      {/* Hero Media */}
      <div className="relative h-[33vh] overflow-hidden">
        {activity.media_type === "video" && activity.video_url ? (
          <video
            src={activity.video_url}
            poster={activity.image_url || undefined}
            className="w-full h-full object-cover"
            muted
            loop
            playsInline
            autoPlay
          />
        ) : (
          <img
            src={activity.image_url || "https://images.unsplash.com/photo-1555939594-58d7cb561ad1?w=1200&q=80"}
            alt={localizedActivity.title}
            className="w-full h-full object-cover"
          />
        )}
        <div className="absolute inset-0 bg-gradient-to-t from-background/90 to-transparent" />
        
        {/* Back Button */}
        <Button
          asChild
          variant="secondary"
          size="icon"
          className="absolute top-4 left-4"
        >
          <button onClick={goBack}>
            <ChevronLeft className="w-5 h-5" />
          </button>
        </Button>
        
        {/* Terms Agreement Warning for Merchants/Supervisors */}
        {user && isMerchantOrSupervisor && profile && !profile.activity_terms_agreed && (
          <Link 
            to="/profile?tab=activities"
            className="absolute top-4 left-16 bg-destructive/95 backdrop-blur-sm text-destructive-foreground text-xs px-3 py-1.5 rounded-full shadow-lg whitespace-nowrap animate-pulse flex items-center gap-1.5 hover:bg-destructive transition-colors"
          >
            <ShieldAlert className="w-3.5 h-3.5" />
            {t("activities.termsNotAgreed")}
          </Link>
        )}
        
        {/* Top Right Actions */}
        <div className="absolute top-4 right-4 flex gap-2 items-start">
          {/* Draft Preview Badge - only for admins */}
          {activity.status === "draft" && isAdmin && (
            <Badge variant="outline" className="bg-amber-500/90 text-white border-amber-600">
              <FileEdit className="w-3 h-3 mr-1" />
              {t("admin.activities.draftPreview")}
            </Badge>
          )}
          {activity.pinned && (
            <Badge className="bg-accent">
              {t("activities.pinned")}
            </Badge>
          )}
          
          {/* Report Button */}
          <ReportDialog
            targetType="activity"
            targetId={activity.id}
            onLoginRequired={() => setShowLoginDialog(true)}
            trigger={
              <Button
                variant="secondary"
                size="icon"
                className="shadow-lg"
              >
                <ShieldAlert className="w-5 h-5" />
              </Button>
            }
          />
          
          {/* Share Button with hint */}
          <div className="relative">
            <Button
              variant="secondary"
              size="icon"
              className="shadow-lg relative"
              onClick={handleShareClick}
            >
              <Share2 className="w-5 h-5" />
              {/* Small gift icon indicator when coupon is available */}
              {hasCouponAvailable && !hasSharedCoupon && (
                <span className="absolute -top-1 -right-1 bg-primary text-primary-foreground rounded-full w-4 h-4 flex items-center justify-center">
                  <Gift className="w-2.5 h-2.5" />
                </span>
              )}
              {/* Checkmark when already claimed */}
              {hasCouponAvailable && hasSharedCoupon && (
                <span className="absolute -top-1 -right-1 bg-green-500 text-white rounded-full w-4 h-4 flex items-center justify-center">
                  <Check className="w-2.5 h-2.5" />
                </span>
              )}
            </Button>
            
            {/* Coupon hint for logged-in users who haven't shared */}
            {user && hasCouponAvailable && !hasSharedCoupon && showCouponHint && (
              <div className="absolute top-full right-0 mt-2 bg-primary/95 backdrop-blur-sm text-primary-foreground text-xs px-3 py-1.5 rounded-full shadow-lg whitespace-nowrap animate-pulse z-10">
                <Gift className="w-3 h-3 inline mr-1" />
                {t("activities.shareToGetCoupon")}
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="container mx-auto max-w-6xl px-4 -mt-20 relative z-10 pb-12">
        <Card className="shadow-large">
          <CardHeader className="relative">
            {/* Handbook Button - Desktop/Tablet: Top Right */}
            <div className="hidden sm:block absolute top-4 right-4">
              <GlobalHandbookDialog>
                <Button variant="outline" size="sm" className="gap-2">
                  <FileText className="w-4 h-4" />
                  {t("activities.handbook.button")}
                </Button>
              </GlobalHandbookDialog>
            </div>
            
            <div className="flex flex-col gap-4 sm:pr-32">
              <div className="flex items-center gap-2 flex-wrap">
                <Badge variant={isOngoing ? "default" : "secondary"}>
                  {isOngoing ? t("activities.ongoing") : t("activities.ended")}
                </Badge>
                {activity.repeat_mode && activity.repeat_mode !== "none" && activity.repeat_mode !== "days_before" && (
                  <Badge variant="outline">
                    {t(`activities.repeat.${activity.repeat_mode}`)}
                  </Badge>
                )}
                {/* Service Type Badge */}
                {activity.service_type && (
                  <Badge variant="outline" className="flex items-center gap-1.5">
                    {activity.service_type === "dine_in" && <UtensilsCrossed className="w-3.5 h-3.5" />}
                    {activity.service_type === "takeaway" && <ShoppingBag className="w-3.5 h-3.5" />}
                    {activity.service_type === "both" && (
                      <>
                        <UtensilsCrossed className="w-3.5 h-3.5" />
                        <ShoppingBag className="w-3.5 h-3.5" />
                      </>
                    )}
                    {t(`activities.serviceType.${activity.service_type}`)}
                  </Badge>
                )}
                
                {/* Handbook Button - Mobile: Inline with badges */}
                <div className="sm:hidden">
                  <GlobalHandbookDialog>
                    <Button variant="outline" size="sm" className="gap-1.5 h-7 px-2">
                      <FileText className="w-3.5 h-3.5" />
                      {t("activities.handbook.button")}
                    </Button>
                  </GlobalHandbookDialog>
                </div>
              </div>
              
              <CardTitle className="text-3xl">{localizedActivity.title}</CardTitle>

              <div className="flex flex-col sm:flex-row sm:flex-wrap gap-x-6 gap-y-2 text-sm text-muted-foreground">
                <div className="flex items-center gap-2 whitespace-nowrap">
                  <Calendar className="w-4 h-4 shrink-0" />
                  <span>
                    {format(startDate, "PPP")}
                    {endDate && ` - ${format(endDate, "PPP")}`}
                  </span>
                </div>
                <ActivitySubscriberCount 
                  activityId={id!} 
                  initialCount={subscriberCount} 
                />
                <ActivityShareCount 
                  activityId={id!} 
                  initialCount={shareCount} 
                />
                <div className="flex items-center gap-2 whitespace-nowrap">
                  <Store className="w-4 h-4 shrink-0" />
                  <span>{activityRestaurants?.length || 0} {t("activities.restaurantsParticipating")}</span>
                </div>
                {/* Creator Info */}
                <div className="flex items-center gap-2 whitespace-nowrap">
                  <UserCircle className="w-4 h-4 shrink-0" />
                  <span>{t("activities.creatorLabel")}</span>
                  {creator?.isAdmin ? (
                    <div className="flex items-center gap-1">
                      <img src={platformLogo} alt="Platform" className="w-4 h-4 rounded-full object-contain" />
                      <span className="font-medium">{t("activities.createdByPlatform")}</span>
                    </div>
                  ) : creator?.restaurant ? (
                    <Link 
                      to={`/restaurant/${creator.restaurant.id}`}
                      className="flex items-center gap-1"
                      onClick={(e) => e.stopPropagation()}
                    >
                      {creator.avatar_url ? (
                        <Avatar className="w-4 h-4">
                          <AvatarImage src={creator.avatar_url} alt="Creator" />
                          <AvatarFallback className="text-[8px]">
                            {creator.restaurant.name.charAt(0)}
                          </AvatarFallback>
                        </Avatar>
                      ) : (
                        <div className="w-4 h-4 rounded-full bg-muted flex items-center justify-center">
                          <span className="text-[8px] font-medium">
                            {creator.restaurant.name.charAt(0)}
                          </span>
                        </div>
                      )}
                      <span className="text-primary font-medium hover:underline">
                        {(() => {
                          const lang = i18n.language;
                          if (lang === "zh") return creator.restaurant.name;
                          if (lang === "pt") return creator.restaurant.name_pt || creator.restaurant.name_en || creator.restaurant.name;
                          return creator.restaurant.name_en || creator.restaurant.name;
                        })()}
                      </span>
                    </Link>
                  ) : (
                    <div className="flex items-center gap-1">
                      <img src={platformLogo} alt="Platform" className="w-4 h-4 rounded-full object-contain" />
                      <span className="font-medium">{t("activities.createdByPlatform")}</span>
                    </div>
                  )}
                </div>
              </div>

              {/* Participation and Subscription buttons */}
              {user && (
                <div className="flex flex-col sm:flex-row gap-3 w-full sm:w-auto">
                  {/* Merchant/Supervisor participation button */}
                  {isMerchantOrSupervisor && myRestaurants.length > 0 && (
                    profile?.activity_terms_agreed ? (
                      <Button
                        onClick={handleToggleActivityParticipation}
                        disabled={toggleParticipation.isPending}
                        size="lg"
                        variant={hasParticipatingRestaurants ? "outline" : "default"}
                        className="w-full sm:w-auto"
                      >
                        {isSupervisor ? (
                          <>
                            <Store className="w-4 h-4 mr-2" />
                            选择参与的餐厅
                          </>
                        ) : (
                          hasParticipatingRestaurants ? (
                            <>
                              <Check className="w-4 h-4 mr-2" />
                              退出活动
                            </>
                          ) : (
                            <>
                              <Store className="w-4 h-4 mr-2" />
                              参与活动
                            </>
                          )
                        )}
                      </Button>
                    ) : (
                      <Button
                        onClick={() => setTermsDialogOpen(true)}
                        size="lg"
                        variant="outline"
                        className="w-full sm:w-auto text-muted-foreground"
                      >
                        {t("activities.agreeTermsFirst")}
                      </Button>
                    )
                  )}

                  {/* Favorite button */}
                  <Button
                    onClick={handleToggleSubscription}
                    disabled={toggleSubscription.isPending}
                    size="lg"
                    variant={isSubscribed ? "outline" : "secondary"}
                    className="w-full sm:w-auto"
                  >
                    {isSubscribed ? (
                      <>
                        <Heart className="w-4 h-4 mr-2 fill-current" />
                        {t("activities.favorited") || "已收藏"}
                      </>
                    ) : (
                      <>
                        <Heart className="w-4 h-4 mr-2" />
                        {t("activities.favorite") || "收藏活动"}
                      </>
                    )}
                  </Button>
                </div>
              )}


              {!user && (
                <div className="space-y-2">
                  <p className="text-sm text-muted-foreground">
                    <Trans
                      i18nKey="activities.signInToJoin"
                      components={{
                        login: <a href="/auth" className="text-primary hover:underline font-medium" />
                      }}
                    />
                  </p>
                  <p className="text-xs text-muted-foreground/80 flex items-center gap-1.5">
                    <Users className="w-3.5 h-3.5" />
                    {t("activities.signInToJoinHint")}
                  </p>
                </div>
              )}
            </div>
          </CardHeader>

          <CardContent className="space-y-6">
            {/* Activity Content */}
            <div>
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-2xl font-bold">{t("activities.about")}</h2>
                <TranslateButton 
                  text={`${localizedActivity.content}${localizedActivity.usage_instructions ? '\n---SECTION---\n' + localizedActivity.usage_instructions : ''}`}
                  onTranslation={(translated) => {
                    setTranslatedContent(translated);
                  }}
                />
              </div>
              <div 
                className="prose prose-sm max-w-none text-muted-foreground
                  prose-headings:text-foreground prose-headings:font-semibold
                  prose-h1:text-2xl prose-h2:text-xl prose-h3:text-lg
                  prose-p:leading-relaxed prose-p:my-3
                  prose-strong:text-foreground prose-strong:font-semibold
                  prose-ul:my-3 prose-ol:my-3
                  prose-li:my-1
                  prose-a:text-primary prose-a:no-underline hover:prose-a:underline
                  [&_*]:!text-inherit [&_span[style*='color']]:!text-muted-foreground"
                dangerouslySetInnerHTML={{ __html: translatedContent 
                  ? (translatedContent.includes('---SECTION---') ? translatedContent.split('---SECTION---')[0].trim() : translatedContent)
                  : localizedActivity.content }}
              />
            </div>

            {/* Usage Instructions - Only show if content exists */}
            {(localizedActivity.usage_instructions || (translatedContent && translatedContent.includes('---SECTION---'))) && (
              <>
                <Separator />
                <div>
                  <h2 className="text-2xl font-bold mb-4 flex items-center gap-2">
                    <BookOpen className="w-6 h-6 text-primary" />
                    {t("activities.usageInstructions")}
                  </h2>
                  <div 
                    className="prose prose-sm max-w-none text-muted-foreground
                      prose-headings:text-foreground prose-headings:font-semibold
                      prose-h1:text-2xl prose-h2:text-xl prose-h3:text-lg
                      prose-p:leading-relaxed prose-p:my-3
                      prose-strong:text-foreground prose-strong:font-semibold
                      prose-ul:my-3 prose-ol:my-3
                      prose-li:my-1
                      prose-a:text-primary prose-a:no-underline hover:prose-a:underline"
                    dangerouslySetInnerHTML={{ __html: translatedContent && translatedContent.includes('---SECTION---')
                      ? translatedContent.split('---SECTION---')[1].trim()
                      : localizedActivity.usage_instructions }}
                  />
                </div>
              </>
            )}


            <Separator />

            {/* Participating Restaurants */}
            {restaurantsLoading ? (
              <div className="flex justify-center py-8">
                <Loader2 className="w-6 h-6 animate-spin text-primary" />
              </div>
            ) : activityRestaurants && activityRestaurants.length > 0 ? (
              <div className="space-y-6">
                {/* Collapsible Restaurant List - Now on top */}
                <Collapsible open={isRestaurantsOpen} onOpenChange={setIsRestaurantsOpen}>
                  <Card className="border-primary/20 shadow-sm hover:shadow-md transition-shadow duration-300 overflow-hidden">
                    <CardHeader className="pb-3">
                      <CollapsibleTrigger asChild>
                        <div className="flex items-center justify-between cursor-pointer group">
                          <CardTitle className="text-lg font-semibold flex items-center gap-2 transition-colors duration-200 group-hover:text-primary">
                            <Store className="w-5 h-5 transition-transform duration-300 group-hover:scale-110" />
                            {t("activities.participatingRestaurants")}
                          </CardTitle>
                          <div className="flex items-center gap-2">
                            <Badge variant="secondary" className="transition-opacity duration-200">
                              {isRestaurantsOpen ? t("common.showLess") : t("common.showDetails")}
                            </Badge>
                            <div className="transition-transform duration-300 ease-in-out" style={{ transform: isRestaurantsOpen ? 'rotate(180deg)' : 'rotate(0deg)' }}>
                              <ChevronDown className="w-5 h-5 text-muted-foreground group-hover:text-primary" />
                            </div>
                          </div>
                        </div>
                      </CollapsibleTrigger>
                    </CardHeader>
                    <CollapsibleContent className="overflow-hidden transition-all duration-500 ease-in-out data-[state=closed]:animate-accordion-up data-[state=open]:animate-accordion-down">
                      <CardContent className="pt-0 pb-6 space-y-4">
                        {/* Location sorting button */}
                        <div className="flex items-center justify-end">
                          {locationEnabled ? (
                            <Badge 
                              variant="default" 
                              className="flex items-center gap-1.5 cursor-pointer hover:opacity-80 transition-opacity"
                              onClick={handleDisableLocation}
                            >
                              <Navigation className="w-3.5 h-3.5" />
                              {t("activities.sortByLocationEnabled")}
                            </Badge>
                          ) : (
                            <Button
                              variant="outline"
                              size="sm"
                              onClick={handleRequestLocation}
                              disabled={isLoadingLocation}
                            >
                              {isLoadingLocation ? (
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                              ) : (
                                <Navigation className="w-4 h-4 mr-2" />
                              )}
                              {t("activities.enableLocationSort")}
                            </Button>
                          )}
                        </div>
                        {/* Restaurant list */}
                        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-4">
                          {(showAllRestaurants ? filteredRestaurants : filteredRestaurants.slice(0, 6)).map((ar, index) => {
                            const restaurant = localizeRestaurant(ar.restaurants);
                            return (
                              <Card 
                                key={ar.id} 
                                className="overflow-hidden hover:shadow-lg transition-all duration-300 opacity-0 animate-fade-in h-full flex flex-col"
                                style={{ 
                                  animationDelay: `${index * 50}ms`,
                                  animationFillMode: 'forwards'
                                }}
                              >
                                <Link 
                                  to={`/restaurant/${ar.restaurant_id}`}
                                  state={{ fromActivity: activity.id }}
                                  className="block"
                                >
                                  <div className="relative h-40 overflow-hidden flex-shrink-0">
                                    <img
                                      src={ar.restaurants.image_url || "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=400&q=80"}
                                      alt={restaurant.name}
                                      className="w-full h-full object-cover transition-transform hover:scale-105"
                                    />
                                    {restaurant.type && restaurant.type.length > 0 && (
                                      <div className="absolute top-2 left-2 flex flex-wrap gap-1">
                                        {restaurant.type.slice(0, 3).map((type: string, typeIndex: number) => (
                                          <Badge key={typeIndex} className="bg-primary">
                                            {type}
                                          </Badge>
                                        ))}
                                      </div>
                                    )}
                                  </div>
                                </Link>
                                <CardContent className="pt-4 pb-4 flex flex-col flex-grow">
                                  <Link 
                                    to={`/restaurant/${ar.restaurant_id}`}
                                    state={{ fromActivity: activity.id }}
                                    className="block"
                                  >
                                    <h3 className="font-semibold text-lg mb-2 line-clamp-1 hover:text-primary transition-colors">
                                      {formatTrademarkSymbols(restaurant.name)}
                                    </h3>
                                    <div className="flex items-center gap-2 text-sm text-muted-foreground mb-3">
                                      <MapPin className="w-4 h-4 flex-shrink-0" />
                                      <span className="line-clamp-1">{ar.restaurants.address}</span>
                                    </div>
                                  </Link>
                                  {/* Rating and Distance */}
                                  <div className="flex items-center justify-between pt-3 border-t border-border/50">
                                    <div className="flex items-center gap-1">
                                      <Star className={`w-4 h-4 ${ar.restaurants.rating ? "fill-accent text-accent" : "text-muted-foreground"}`} />
                                      {ar.restaurants.rating ? (
                                        <span className="font-semibold text-sm">
                                          {ar.restaurants.rating.toFixed(1)}
                                        </span>
                                      ) : (
                                        <span className="text-xs text-muted-foreground text-center whitespace-nowrap">
                                          {t("restaurant.noRatingLine1")}<br />{t("restaurant.noRatingLine2")}
                                        </span>
                                      )}
                                    </div>
                                    {ar.distance !== undefined && (
                                      <div className="flex items-center gap-1">
                                        <Navigation className="w-4 h-4 text-primary" />
                                        <span className="font-semibold text-sm text-foreground">
                                          {ar.distance.toFixed(1)} km
                                        </span>
                                      </div>
                                    )}
                                  </div>
                                  {/* Order Online button */}
                                  {(ar.restaurants as any).takeaway_url && (
                                    <div className="flex gap-2 mt-3 pt-3 border-t border-border/50">
                                      <Button
                                        size="sm"
                                        variant="outline"
                                        className="flex-1"
                                        onClick={() => handleExternalLinkClick((ar.restaurants as any).takeaway_url!, ar.restaurants.id)}
                                      >
                                        <UtensilsCrossed className="w-4 h-4 mr-1" />
                                        {t("restaurant.orderOnline")}
                                      </Button>
                                    </div>
                                  )}
                                </CardContent>
                              </Card>
                            );
                          })}
                        </div>
                        
                        {/* Show More Button */}
                        {filteredRestaurants.length > 6 && !showAllRestaurants && (
                          <Button
                            variant="outline"
                            className="w-full hover:bg-primary hover:text-primary-foreground transition-all duration-200"
                            onClick={() => setShowAllRestaurants(true)}
                          >
                            <ChevronDown className="w-4 h-4 mr-2" />
                            查看更多 ({filteredRestaurants.length - 6} 个餐厅)
                          </Button>
                        )}
                      </CardContent>
                    </CollapsibleContent>
                  </Card>
                </Collapsible>

                {/* Participating Restaurants Map - Now below */}
                <div>
                  <h2 className="text-2xl font-bold flex items-center gap-2 mb-4">
                    <MapPin className="w-6 h-6" />
                    {t("activities.participatingRestaurants")} ({filteredRestaurants.length})
                  </h2>
                  
                  {/* Map showing filtered restaurants */}
                  <ActivityParticipationMap 
                    restaurants={filteredRestaurants}
                    onMarkerClick={handleMarkerClick}
                  />
                </div>
              </div>
            ) : null}


            {/* Comments Section */}
            <RestaurantComments restaurantId={activity.id} targetType="activity" />

            {/* Community Entry CTA */}
            <CommunityEntryCTA />

            {/* Guess You Like */}
            <GuessYouLike currentId={activity.id} />
          </CardContent>
        </Card>
      </div>

      {/* Restaurant Selection Dialog for Supervisor */}
      {isSupervisor && (
        <SelectRestaurantsDialog
          open={selectRestaurantsDialogOpen}
          onOpenChange={setSelectRestaurantsDialogOpen}
          restaurants={myRestaurants}
          participatingRestaurantIds={participatingRestaurantIds}
          onConfirm={handleConfirmRestaurantSelection}
          isPending={toggleParticipation.isPending}
          isParticipating={hasParticipatingRestaurants}
        />
      )}

      {/* Activity Terms Agreement Dialog */}
      {isMerchantOrSupervisor && (
        <ActivityTermsAgreement
          isAgreed={profile?.activity_terms_agreed || false}
          agreedAt={profile?.activity_terms_agreed_at || null}
          open={termsDialogOpen}
          onOpenChange={setTermsDialogOpen}
        />
      )}


      {/* Share for Coupon Dialog */}
      <ShareForCouponDialog
        open={showShareDialog}
        onOpenChange={setShowShareDialog}
        activityTitle={localizedActivity?.title || ""}
        activityId={id!}
        onShareComplete={handleShareComplete}
        onShareAction={handleShareAction}
        isProcessing={isClaimingCoupon}
        hasAlreadyClaimed={hasSharedCoupon}
      />

      <LocationPermissionDialog
        open={showLocationDialog}
        onOpenChange={setShowLocationDialog}
        onConfirm={requestLocation}
      />

      {/* Login Required Dialog */}
      <AlertDialog open={showLoginDialog} onOpenChange={setShowLoginDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t("activities.loginRequired")}</AlertDialogTitle>
            <AlertDialogDescription>
              {t("activities.loginRequiredMessage")}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t("common.cancel")}</AlertDialogCancel>
            <AlertDialogAction onClick={() => navigate("/auth")}>
              {t("activities.goToLogin")}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* External Link Confirmation Dialog - iOS compatible */}
      <ExternalLinkConfirmDialog
        open={externalLinkDialogOpen}
        onOpenChange={setExternalLinkDialogOpen}
        onConfirm={handleConfirmExternalLink}
        url={pendingExternalUrl || undefined}
      />
      
      {/* Smart Share Drawer for WebView environments */}
      {SmartShareDrawer}
    </div>
    </PullToRefresh>
  );
};

export default ActivityDetail;
