import { useState, useEffect, useCallback } from "react";
import { Forward } from "lucide-react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { useQueryClient } from "@tanstack/react-query";

interface ActivityShareCountProps {
  activityId: string;
  initialCount?: number;
}

export const ActivityShareCount = ({ activityId, initialCount = 0 }: ActivityShareCountProps) => {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const [count, setCount] = useState(initialCount);

  // Function to fetch fresh count
  const fetchCount = useCallback(async () => {
    const { count: newCount } = await supabase
      .from("activity_shares")
      .select("*", { count: "exact", head: true })
      .eq("activity_id", activityId);
    
    if (newCount !== null) {
      setCount(newCount);
    }
  }, [activityId]);

  // Sync with initial value changes (from query invalidation)
  useEffect(() => {
    setCount(initialCount);
  }, [initialCount]);

  // Subscribe to realtime updates
  useEffect(() => {
    const channel = supabase
      .channel(`share-count-${activityId}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'activity_shares',
          filter: `activity_id=eq.${activityId}`
        },
        () => {
          // Fetch updated count when any change occurs
          fetchCount();
          // Also invalidate the query cache
          queryClient.invalidateQueries({ queryKey: ["shareCount", activityId] });
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [activityId, fetchCount, queryClient]);

  return (
    <div className="flex items-center gap-2 whitespace-nowrap">
      <Forward className="w-4 h-4 shrink-0" />
      <span>{count} {t("activities.shareCount")}</span>
    </div>
  );
};
