import { formatTrademarkSymbols } from "@/lib/textFormatting";
import { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/label";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Store, Loader2, Check } from "lucide-react";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";

interface Restaurant {
  id: string;
  name: string;
  name_en: string | null;
  name_pt: string | null;
  type: string[];
  type_en: string[] | null;
  type_pt: string[] | null;
  address: string;
  image_url: string | null;
}

interface SelectRestaurantsDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  restaurants: Restaurant[];
  participatingRestaurantIds: string[];
  onConfirm: (selectedRestaurantIds: string[]) => void;
  isPending: boolean;
  isParticipating: boolean;
}

const SelectRestaurantsDialog = ({
  open,
  onOpenChange,
  restaurants,
  participatingRestaurantIds,
  onConfirm,
  isPending,
  isParticipating,
}: SelectRestaurantsDialogProps) => {
  const { t } = useTranslation();
  const { localizeRestaurant } = useLocalizedContent();
  const [selectedRestaurantIds, setSelectedRestaurantIds] = useState<string[]>([]);

  // Reset selected restaurants when dialog opens or participatingRestaurantIds changes
  useEffect(() => {
    if (open) {
      setSelectedRestaurantIds(participatingRestaurantIds);
    }
  }, [open, participatingRestaurantIds]);

  const handleToggleRestaurant = (restaurantId: string) => {
    setSelectedRestaurantIds((prev) =>
      prev.includes(restaurantId)
        ? prev.filter((id) => id !== restaurantId)
        : [...prev, restaurantId]
    );
  };

  const handleSelectAll = () => {
    if (selectedRestaurantIds.length === restaurants.length) {
      setSelectedRestaurantIds([]);
    } else {
      setSelectedRestaurantIds(restaurants.map((r) => r.id));
    }
  };

  const handleConfirm = () => {
    onConfirm(selectedRestaurantIds);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-[90vw] sm:max-w-[600px] max-h-[90vh] overflow-hidden flex flex-col">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Store className="w-5 h-5" />
            选择参与的餐厅
          </DialogTitle>
          <DialogDescription>
            勾选要参与活动的餐厅，取消勾选将退出活动
          </DialogDescription>
        </DialogHeader>

        <div className="flex-1 overflow-y-auto space-y-4 py-4">
          {/* Select All */}
          <div className="flex items-center gap-2 pb-2 border-b">
            <Checkbox
              id="select-all"
              checked={selectedRestaurantIds.length === restaurants.length}
              onCheckedChange={handleSelectAll}
            />
            <Label htmlFor="select-all" className="cursor-pointer font-semibold">
              全选/取消全选 ({selectedRestaurantIds.length}/{restaurants.length})
            </Label>
          </div>

          {/* Restaurant List */}
          <div className="space-y-3">
            {restaurants.map((restaurant) => {
              const localizedRestaurant = localizeRestaurant(restaurant);
              const isSelected = selectedRestaurantIds.includes(restaurant.id);
              const wasParticipating = participatingRestaurantIds.includes(restaurant.id);

              return (
                <Card
                  key={restaurant.id}
                  className={`transition-all ${
                    isSelected
                      ? "border-primary bg-primary/5"
                      : "border-border hover:border-primary/50"
                  }`}
                >
                  <CardContent className="p-4">
                    <div className="flex items-center gap-3">
                      <Checkbox
                        id={restaurant.id}
                        checked={isSelected}
                        onCheckedChange={() => handleToggleRestaurant(restaurant.id)}
                      />
                      <div className="flex-1 min-w-0">
                        <Label
                          htmlFor={restaurant.id}
                          className="cursor-pointer flex items-center gap-2"
                        >
                          <span className="font-semibold truncate">
                            {formatTrademarkSymbols(localizedRestaurant.name)}
                          </span>
                          {wasParticipating && (
                            <Badge variant="secondary" className="text-xs">
                              <Check className="w-3 h-3 mr-1" />
                              已参与
                            </Badge>
                          )}
                        </Label>
                        <p className="text-sm text-muted-foreground truncate">
                          {restaurant.address}
                        </p>
                        {localizedRestaurant.type && localizedRestaurant.type.length > 0 && (
                          <div className="flex gap-1 mt-1 flex-wrap">
                            {localizedRestaurant.type.slice(0, 2).map((type, index) => (
                              <Badge
                                key={index}
                                variant="outline"
                                className="text-xs"
                              >
                                {type}
                              </Badge>
                            ))}
                          </div>
                        )}
                      </div>
                    </div>
                  </CardContent>
                </Card>
              );
            })}
          </div>
        </div>

        <DialogFooter>
          <Button
            variant="outline"
            onClick={() => onOpenChange(false)}
            disabled={isPending}
          >
            {t("common.cancel")}
          </Button>
          <Button onClick={handleConfirm} disabled={isPending}>
            {isPending ? (
              <>
                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                {t("common.loading")}
              </>
            ) : (
              <>
                <Check className="w-4 h-4 mr-2" />
                确认 ({selectedRestaurantIds.length})
              </>
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};

export default SelectRestaurantsDialog;
